  private static void assertGolden(String layerId, long seed, int radius, int[] flatXZ) {
    StructureLayer layer = StructureCatalog.byId(layerId).orElseThrow();
    List<FoundStructure> found = SeedStructureLocator.locate(layer, seed, radius, ALWAYS_VALID);
    assertEquals(toSet(flatXZ), toSet(found), layerId + " seed=" + seed);
  }

  private static Set<Long> toSet(List<FoundStructure> found) {
    Set<Long> set = new HashSet<>();
    for (FoundStructure f : found) {
      set.add(pack(f.x(), f.z()));
    }
    return set;
  }

  private static Set<Long> toSet(int[] flatXZ) {
    Set<Long> set = new HashSet<>();
    for (int i = 0; i < flatXZ.length; i += 2) {
      set.add(pack(flatXZ[i], flatXZ[i + 1]));
    }
    return set;
  }

  private static long pack(int x, int z) {
    return (((long) x) << 32) ^ (z & 0xFFFFFFFFL);
  }


